**New module-level state**:

```typescript
import { getTheme, listThemes, DEFAULT_THEME_ID, type Theme } from "@t3tools/shared/themes";

type ThemePreference = string; // a theme id, or "system"
interface ThemeSnapshot {
  preference: ThemePreference;     // "system" | theme id
  resolvedThemeId: string;         // always a concrete theme id
  systemDark: boolean;
}

const STORAGE_KEY = "t3code:color-theme";
const LEGACY_STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";
const DEFAULT_LIGHT_THEME_ID = "t3-light";
const DEFAULT_DARK_THEME_ID = "t3-dark";
```

**Key helper functions**:

```typescript
function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function migrateFromLegacy(): ThemePreference {
  const legacy = localStorage.getItem(LEGACY_STORAGE_KEY);
  if (legacy === "light") return DEFAULT_LIGHT_THEME_ID;
  if (legacy === "dark") return DEFAULT_DARK_THEME_ID;
  if (legacy === "system") return "system";
  return "system";
}

function getStoredPreference(): ThemePreference {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw !== null) {
    // Validate it's either "system" or a known theme id
    if (raw === "system") return "system";
    if (getTheme(raw) !== undefined) return raw;
  }
  // Fall back to migration
  return migrateFromLegacy();
}

function resolveThemeId(preference: ThemePreference): string {
  if (preference === "system") {
    return getSystemDark() ? DEFAULT_DARK_THEME_ID : DEFAULT_LIGHT_THEME_ID;
  }
  return getTheme(preference) !== undefined ? preference : DEFAULT_THEME_ID;
}
```

**CSS variable application** -- the core new logic:

```typescript
/** Map camelCase ThemeColors key to CSS custom property name */
const COLOR_KEY_TO_CSS_VAR: Record<string, string> = {
  background: "--background",
  foreground: "--foreground",
  card: "--card",
  cardForeground: "--card-foreground",
  popover: "--popover",
  popoverForeground: "--popover-foreground",
  primary: "--primary",
  primaryForeground: "--primary-foreground",
  secondary: "--secondary",
  secondaryForeground: "--secondary-foreground",
  muted: "--muted",
  mutedForeground: "--muted-foreground",
  accent: "--accent",
  accentForeground: "--accent-foreground",
  destructive: "--destructive",
  destructiveForeground: "--destructive-foreground",
  border: "--border",
  input: "--input",
  ring: "--ring",
  info: "--info",
  infoForeground: "--info-foreground",
  success: "--success",
  successForeground: "--success-foreground",
  warning: "--warning",
  warningForeground: "--warning-foreground",
};

function applyTheme(themeId: string, suppressTransitions = false): void {
  const theme = getTheme(themeId);
  if (!theme) return;
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Toggle .dark class based on theme's colorScheme
  root.classList.toggle("dark", theme.colorScheme === "dark");

  // Set color-scheme for browser UA styling
  root.style.colorScheme = theme.colorScheme;

  // Apply all color CSS custom properties as inline styles
  for (const [key, cssVar] of Object.entries(COLOR_KEY_TO_CSS_VAR)) {
    const value = theme.colors[key as keyof ThemeColors];
    if (value !== undefined) {
      root.style.setProperty(cssVar, value);
    }
  }

  // Apply font overrides if present
  if (theme.fontFamily !== null) {
    root.style.setProperty("--theme-font-family", theme.fontFamily);
  } else {
    root.style.removeProperty("--theme-font-family");
  }
  if (theme.fontSize !== null) {
    root.style.setProperty("--theme-font-size", `${theme.fontSize}px`);
  } else {
    root.style.removeProperty("--theme-font-size");
  }

  if (suppressTransitions) {
    // Force reflow
    // eslint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}
```

**Critical interaction with `index.css`**: The inline styles set via `style.setProperty` on `<html>` will **override** the `:root` CSS declarations (inline styles have higher specificity than ruleset declarations). However, the `@variant dark` block inside `:root` also defines the same properties. Because `@custom-variant dark (&:is(.dark, .dark *))` generates rules at a specificity level *lower* than inline styles, inline overrides always win. This is the desired behavior -- when a named theme is active, its colors take precedence over both the `:root` light defaults and the `@variant dark` overrides.

For the default themes (`t3-dark`, `t3-light`), we could optimize by *removing* inline overrides and letting CSS handle it, but applying inline styles uniformly for all themes is simpler and more predictable.

**`clearThemeOverrides()`** function: For the "system" preference with no custom theme colors, we could clear inline styles and fall back to CSS. However, since "system" resolves to a specific named theme, we always apply via inline styles for consistency.

**`getSnapshot()` and `subscribe()`** are structurally identical to the current implementation but use the new `ThemeSnapshot` shape.

**New exported hook**:

```typescript
export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const theme = getTheme(snapshot.resolvedThemeId)!;
  const resolvedTheme: "light" | "dark" = theme.colorScheme;

  const setTheme = useCallback((next: ThemePreference) => {
    localStorage.setItem(STORAGE_KEY, next);
    const resolvedId = resolveThemeId(next);
    applyTheme(resolvedId, true);
    emitChange();
  }, []);

  useEffect(() => {
    applyTheme(snapshot.resolvedThemeId);
  }, [snapshot.resolvedThemeId]);

  return {
    /** The raw user preference: "system" or a theme id */
    themePreference: snapshot.preference,
    /** The resolved Theme object */
    theme,
    /** "light" | "dark" -- backward-compatible for DiffPanel, ChatMarkdown, etc. */
    resolvedTheme,
    /** All available themes */
    availableThemes: listThemes(),
    /** Set preference to "system" or a theme id */
    setTheme,
  } as const;
}
```

**Backward compatibility**: The return type now includes both `themePreference` and `resolvedTheme`. The old callers that destructure `{ resolvedTheme }` continue to work without changes. The old `{ theme }` property (which was `"light" | "dark" | "system"`) is replaced by `{ themePreference }` (which is `string`). The `{ theme }` property is now a `Theme` object. The settings page and any code that did `theme === "system"` needs updating to use `themePreference === "system"`.

**Module-load initialization** (flash prevention):

```typescript
