const THEMES_BY_ID: ReadonlyMap<string, Theme> = new Map(
  BUILT_IN_THEMES.map((t) => [t.id, t]),
);

export function getTheme(id: string): Theme | undefined {
  return THEMES_BY_ID.get(id);
}

export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

export const DEFAULT_THEME_ID = "t3-dark";
```

Pattern match: follows `getModelOptions()` / `getDefaultModel()` from `model.ts` -- pure functions, exported constants, data defined at module level.

