                  <ProviderModelPicker
                    provider={selectedProvider}
                    model={selectedModelForPickerWithCustomFallback}
                    lockedProvider={lockedProvider}
                    modelOptionsByProvider={modelOptionsByProvider}
                    serviceTierSetting={selectedServiceTierSetting}
