                      ) : null}
                      <Button
                        type="submit"
                        size="sm"
                        className="rounded-full px-4"
                        disabled={
                          activePendingIsResponding ||
                          (activePendingProgress.isLastQuestion
                            ? !activePendingResolvedAnswers
                            : !activePendingProgress.canAdvance)
                        }
                      >
                        {activePendingIsResponding
                          ? "Submitting..."
