/** Color palette for a T3 Code theme. */
export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

/** A complete theme definition used by the T3 Code editor. */
export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

const builtInThemes: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0a0a0b",
      foreground: "#e4e4e7",
      accent: "#6d5dfc",
      sidebar: "#111113",
      editor: "#0a0a0b",
      terminal: "#09090b",
      statusBar: "#111113",
    },
    fontFamily: "ui-monospace, SFMono-Regular, 'SF Mono', Menlo, monospace",
    fontSize: 13,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#18181b",
      accent: "#6d5dfc",
      sidebar: "#f4f4f5",
      editor: "#ffffff",
      terminal: "#fafafa",
      statusBar: "#f4f4f5",
    },
    fontFamily: "ui-monospace, SFMono-Regular, 'SF Mono', Menlo, monospace",
    fontSize: 13,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#0b0d1a",
      foreground: "#c8cad8",
      accent: "#7c6ef6",
      sidebar: "#0e1025",
      editor: "#0b0d1a",
      terminal: "#080a14",
      statusBar: "#0e1025",
    },
    fontFamily: "ui-monospace, SFMono-Regular, 'SF Mono', Menlo, monospace",
    fontSize: 13,
  },
];

const themeMap = new Map<string, Theme>(
  builtInThemes.map((theme) => [theme.id, theme]),
);

/** Look up a theme by its unique id. Returns `undefined` when unknown. */
export function getTheme(id: string): Theme | undefined {
  return themeMap.get(id);
}

/** Return every registered built-in theme. */
export function listThemes(): readonly Theme[] {
  return builtInThemes;
}

