import { createContext, useCallback, useContext, useEffect, useMemo, useState, type ReactNode } from "react";
import { type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:custom-theme";
const DEFAULT_THEME_ID = "t3-dark";

interface ThemeContextValue {
  /** The currently active theme object. */
  theme: Theme;
  /** Switch to a different theme by its id. Unknown ids fall back to the default. */
  setTheme: (id: string) => void;
  /** Every registered built-in theme. */
  availableThemes: readonly Theme[];
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

function getStoredThemeId(): string {
  try {
    return localStorage.getItem(STORAGE_KEY) ?? DEFAULT_THEME_ID;
  } catch {
    return DEFAULT_THEME_ID;
  }
}

function resolveTheme(id: string): Theme {
  return getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
}

function applyThemeCssProperties(theme: Theme): void {
  const root = document.documentElement;
  root.style.setProperty("--theme-background", theme.colors.background);
  root.style.setProperty("--theme-foreground", theme.colors.foreground);
  root.style.setProperty("--theme-accent", theme.colors.accent);
  root.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  root.style.setProperty("--theme-editor", theme.colors.editor);
  root.style.setProperty("--theme-terminal", theme.colors.terminal);
  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${String(theme.fontSize)}px`);
}

const availableThemes = listThemes();

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setThemeState] = useState<Theme>(() => {
    const resolved = resolveTheme(getStoredThemeId());
    // Apply immediately so CSS properties are ready before first paint.
    applyThemeCssProperties(resolved);
    return resolved;
  });

  const setTheme = useCallback((id: string) => {
    const resolved = resolveTheme(id);
    localStorage.setItem(STORAGE_KEY, resolved.id);
    setThemeState(resolved);
    applyThemeCssProperties(resolved);
  }, []);

  // Re-apply when theme changes (covers HMR / React strict-mode double-mount).
  useEffect(() => {
    applyThemeCssProperties(theme);
  }, [theme]);

  // Sync theme when another tab changes it.
  useEffect(() => {
    const handleStorage = (e: StorageEvent) => {
      if (e.key === STORAGE_KEY) {
        const resolved = resolveTheme(e.newValue ?? DEFAULT_THEME_ID);
        setThemeState(resolved);
        applyThemeCssProperties(resolved);
      }
    };
    window.addEventListener("storage", handleStorage);
    return () => window.removeEventListener("storage", handleStorage);
  }, []);

  const value = useMemo<ThemeContextValue>(
    () => ({ theme, setTheme, availableThemes }),
    [theme, setTheme],
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

/**
 * Access the current color theme, a setter, and the list of available themes.
 * Must be rendered inside a `<ThemeProvider>`.
 */
export function useTheme(): ThemeContextValue {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return context;
}

