import type { ThemeColors } from "@t3tools/shared/themes";
import { useTheme } from "./ThemeProvider";

/** Ordered keys rendered as preview swatches. */
const SWATCH_KEYS: ReadonlyArray<keyof ThemeColors> = [
  "background",
  "foreground",
  "accent",
  "sidebar",
  "editor",
  "terminal",
  "statusBar",
];

export function ThemeSelector() {
  const { theme: activeTheme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((t) => {
        const selected = activeTheme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id)}
          >
            {/* Color swatch previews */}
            <span className="flex shrink-0 gap-1" aria-hidden="true">
              {SWATCH_KEYS.map((key) => (
                <span
                  key={key}
                  className="size-4 rounded-full border border-border/50"
                  style={{ backgroundColor: t.colors[key] }}
                />
              ))}
            </span>

            <span className="flex flex-1 flex-col">
              <span className="text-sm font-medium">{t.name}</span>
              <span className="text-xs opacity-60">
                {t.fontFamily.split(",")[0]?.replace(/['"]/g, "").trim()}, {String(t.fontSize)}px
              </span>
            </span>

            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

